input.file_text:
//+------------------------------------------------------------------+
//|  ORB_BreakoutEA_v3_ORCA_NY_XAUUSD.mq5                           |
//|  Jose's Trading Suite  |  Abril 2026                            |
//|  Sesion: NY Open  |  Pass #2210 (Optimizacion ORCA)             |
//|  Magic: 20260505  |  Prefijo objetos: ORB_v3_ORCA_NY_           |
//|  Base: v2b (InpOrdenExpiraVelas) + Filtro ORCA integrado        |
//|                                                                  |
//|  Parametros optimos:                                             |
//|    SessionHour=17, SessionMinute=0, RangeCandles=5              |
//|    TP=100, SL=50, BE=80, Risk=$25                               |
//|    ORCA: Peso=0.7, Umbral=0.15                                  |
//+------------------------------------------------------------------+
#property copyright "Jose's Trading Suite"
#property version   "3.05"
#property strict

#include <Trade\Trade.mqh>

//--- Enumeraciones
enum ENUM_TRADE_DIR
  {
   DIR_BOTH      = 0,
   DIR_BUY_ONLY  = 1,
   DIR_SELL_ONLY = 2
  };

//+------------------------------------------------------------------+
//|  INPUTS                                                          |
//+------------------------------------------------------------------+
input group "=== SESION ==="
input int              InpSessionHour         = 17;     // Hora inicio sesion (servidor)
input int              InpSessionMinute        = 0;     // Minuto inicio sesion
input int              InpRangeCandles        = 5;      // Velas M5 para construir rango

input group "=== GESTION ==="
input double           InpTP_Pips             = 100.0;  // Take Profit (pips)
input double           InpSL_Pips             = 50.0;   // Stop Loss (pips)
input double           InpBE_Pips             = 80.0;   // BreakEven (0=desactivado)
input double           InpRiskUSD             = 25.0;   // Riesgo por trade (USD)
input ENUM_TRADE_DIR   InpTradeDirection      = DIR_BOTH;// Direccion permitida

input group "=== EXPIRACION ORDENES (v2b) ==="
input int              InpOrdenExpiraVelas    = 0;      // Velas M5 para expirar (0=sin limite)

input group "=== FILTRO ORCA ==="
input bool             InpORCA_Activo         = true;   // Activar filtro ORCA
input double           InpORCA_PesoBullPressure = 0.7;  // Peso BullPressure (0-1)
input double           InpORCA_UmbralScore    = 0.15;   // Umbral score ORCA (0-1)

input group "=== DIAS PERMITIDOS ==="
input bool             InpAllowMonday         = true;
input bool             InpAllowTuesday        = true;
input bool             InpAllowWednesday      = true;
input bool             InpAllowThursday       = true;
input bool             InpAllowFriday         = true;
input bool             InpAllowSaturday       = false;
input bool             InpAllowSunday         = false;

input group "=== CONFIGURACION ==="
input bool             InpOnlyOnePerDay       = true;   // Solo un trade por dia
input long             InpMagicNumber         = 20260505;
input bool             InpShowVisuals         = true;   // Mostrar panel (false en backtest)
input string           InpObjPrefix           = "ORB_v3_ORCA_NY_";

//+------------------------------------------------------------------+
//|  VARIABLES GLOBALES                                              |
//+------------------------------------------------------------------+
CTrade   g_Trade;
double   g_PipSize        = 0.0;

// Estado del rango
bool     g_RangoFormado   = false;
double   g_RangeHigh      = 0.0;
double   g_RangeLow       = 0.0;
datetime g_RangeTime      = 0;

// ORCA score calculado en BuildRange
double   g_ORCA_Score     = 0.0;
ENUM_TRADE_DIR g_DirEfectiva = DIR_BOTH;

// Estado de ordenes
bool     g_OrdenesColocadas  = false;
bool     g_OperadoHoy        = false;
datetime g_OrdenesColocadasTime = 0;
datetime g_UltimaVelaContada = 0;
int      g_VelasDesdeColocacion = 0;

// Tickets
ulong    g_TicketBuy      = 0;
ulong    g_TicketSell     = 0;
ulong    g_TicketPos      = 0;

// Control de dia
datetime g_UltimoDia      = 0;

//+------------------------------------------------------------------+
//|  OnInit                                                          |
//+------------------------------------------------------------------+
int OnInit()
  {
   g_PipSize = _Point * 10.0;
   g_Trade.SetExpertMagicNumber(InpMagicNumber);
   g_Trade.SetDeviationInPoints(30);
   g_Trade.SetTypeFilling(ORDER_FILLING_IOC);

   Print("ORB_v3_ORCA_NY iniciado | Magic=", InpMagicNumber,
         " | Sesion=", InpSessionHour, ":", StringFormat("%02d", InpSessionMinute),
         " | Candles=", InpRangeCandles,
         " | TP=", InpTP_Pips, " SL=", InpSL_Pips, " BE=", InpBE_Pips,
         " | ORCA=", InpORCA_Activo, " Peso=", InpORCA_PesoBullPressure, " Umbral=", InpORCA_UmbralScore);

   ResetDia();
   return INIT_SUCCEEDED;
  }

//+------------------------------------------------------------------+
//|  OnDeinit                                                        |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
  {
   EliminarObjetos();
  }

//+------------------------------------------------------------------+
//|  OnTick                                                          |
//+------------------------------------------------------------------+
void OnTick()
  {
   // Verificar nuevo dia
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);

   datetime inicioDia = StringToTime(StringFormat("%04d.%02d.%02d 00:00", dt.year, dt.mon, dt.day));
   if(inicioDia != g_UltimoDia)
     {
      ResetDia();
      g_UltimoDia = inicioDia;
     }

   // Verificar dia permitido
   if(!DiaPermitido(dt.day_of_week)) return;

   // Si ya opero hoy y OnlyOnePerDay -> solo gestionar
   if(g_OperadoHoy && InpOnlyOnePerDay)
     {
      GestionarPosicion();
      if(InpShowVisuals) ActualizarPanel();
      return;
     }

   // Construir rango si no esta formado
   if(!g_RangoFormado)
     {
      TryBuildRange();
     }

   // Colocar ordenes si rango formado y no colocadas aun
   if(g_RangoFormado && !g_OrdenesColocadas && !g_OperadoHoy)
     {
      ColocarOrdenes();
     }

   // Gestionar expiracion v2b
   if(g_OrdenesColocadas && InpOrdenExpiraVelas > 0)
     {
      GestionarExpiracion();
     }

   // Verificar activacion de ordenes
   if(g_OrdenesColocadas)
     {
      VerificarActivacion();
     }

   // Gestionar posicion abierta
   GestionarPosicion();

   if(InpShowVisuals) ActualizarPanel();
  }

//+------------------------------------------------------------------+
//|  ResetDia                                                        |
//+------------------------------------------------------------------+
void ResetDia()
  {
   g_RangoFormado    = false;
   g_RangeHigh       = 0.0;
   g_RangeLow        = 0.0;
   g_RangeTime       = 0;
   g_ORCA_Score      = 0.0;
   g_DirEfectiva     = DIR_BOTH;
   g_OrdenesColocadas= false;
   g_OperadoHoy      = false;
   g_OrdenesColocadasTime = 0;
   g_UltimaVelaContada    = 0;
   g_VelasDesdeColocacion = 0;
   g_TicketBuy       = 0;
   g_TicketSell      = 0;
   g_TicketPos       = 0;

   EliminarObjetos();
  }

//+------------------------------------------------------------------+
//|  DiaPermitido                                                    |
//+------------------------------------------------------------------+
bool DiaPermitido(int diaSemana)
  {
   switch(diaSemana)
     {
      case 0: return InpAllowSunday;
      case 1: return InpAllowMonday;
      case 2: return InpAllowTuesday;
      case 3: return InpAllowWednesday;
      case 4: return InpAllowThursday;
      case 5: return InpAllowFriday;
      case 6: return InpAllowSaturday;
     }
   return false;
  }

//+------------------------------------------------------------------+
//|  TryBuildRange  — construye rango + calcula ORCA en un solo loop |
//+------------------------------------------------------------------+
void TryBuildRange()
  {
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);

   // Tiempo de inicio de sesion hoy
   datetime sesionInicio = StringToTime(StringFormat("%04d.%02d.%02d %02d:%02d",
                           dt.year, dt.mon, dt.day,
                           InpSessionHour, InpSessionMinute));

   if(TimeCurrent() < sesionInicio) return;

   // Necesitamos InpRangeCandles velas M5 completas desde sesionInicio
   int totalBars = Bars(_Symbol, PERIOD_M5);
   if(totalBars < InpRangeCandles + 2) return;

   // Encontrar la barra que corresponde a sesionInicio
   int barInicio = iBarShift(_Symbol, PERIOD_M5, sesionInicio, false);
   if(barInicio < 0) return;

   // Verificar que todas las velas del rango estan cerradas
   int barFin = barInicio - (InpRangeCandles - 1);
   if(barFin <= 0) return;

   // Construir High/Low + ORCA en un solo loop
   double rangeHigh = 0.0, rangeLow = DBL_MAX;
   double sumBody = 0.0;
   double bullishBody = 0.0;
   int    n = InpRangeCandles;

   for(int i = barInicio; i >= barFin; i--)
     {
      double hi  = iHigh(_Symbol, PERIOD_M5, i);
      double lo  = iLow (_Symbol, PERIOD_M5, i);
      double op  = iOpen(_Symbol, PERIOD_M5, i);
      double cl  = iClose(_Symbol, PERIOD_M5, i);

      if(hi > rangeHigh) rangeHigh = hi;
      if(lo < rangeLow)  rangeLow  = lo;

      double body = MathAbs(cl - op);
      sumBody += body;
      if(cl > op) bullishBody += body;
     }

   if(rangeHigh <= rangeLow) return;

   // MidBias: promedio de cierres normalizado dentro del rango
   double totalRange = rangeHigh - rangeLow;
   double midClose   = 0.0;
   for(int i = barInicio; i >= barFin; i--)
     {
      double cl = iClose(_Symbol, PERIOD_M5, i);
      midClose += (cl - rangeLow) / totalRange;
     }
   midClose /= n;

   double bullPressure = (sumBody > 0.0) ? (bullishBody / sumBody) : 0.5;
   double midBias      = midClose;

   double rawScore = InpORCA_PesoBullPressure * bullPressure +
                     (1.0 - InpORCA_PesoBullPressure) * midBias;
   g_ORCA_Score = rawScore - 0.5;

   // Aplicar filtro ORCA
   g_DirEfectiva = (ENUM_TRADE_DIR)InpTradeDirection;
   if(InpORCA_Activo)
     {
      if(g_ORCA_Score > InpORCA_UmbralScore)
         g_DirEfectiva = DIR_BUY_ONLY;
      else if(g_ORCA_Score < -InpORCA_UmbralScore)
         g_DirEfectiva = DIR_SELL_ONLY;
      else
         g_DirEfectiva = DIR_BOTH;

      if(InpTradeDirection == DIR_BUY_ONLY  && g_DirEfectiva == DIR_SELL_ONLY) g_DirEfectiva = DIR_BUY_ONLY;
      if(InpTradeDirection == DIR_SELL_ONLY && g_DirEfectiva == DIR_BUY_ONLY)  g_DirEfectiva = DIR_SELL_ONLY;
     }

   g_RangeHigh    = rangeHigh;
   g_RangeLow     = rangeLow;
   g_RangeTime    = sesionInicio;
   g_RangoFormado = true;

   Print("RANGO FORMADO | High=", DoubleToString(g_RangeHigh, _Digits),
         " Low=", DoubleToString(g_RangeLow, _Digits),
         " | ORCA Score=", DoubleToString(g_ORCA_Score, 4),
         " | Direccion=", g_DirEfectiva == DIR_BOTH ? "BOTH" :
                          g_DirEfectiva == DIR_BUY_ONLY ? "BUY" : "SELL");

   if(InpShowVisuals) DibujarRango();
  }

//+------------------------------------------------------------------+
//|  CalculateLotSize                                                |
//+------------------------------------------------------------------+
double CalculateLotSize(double slPips)
  {
   double tickValue = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   if(tickSize == 0.0 || tickValue == 0.0) return 0.01;

   double pipValue = (g_PipSize / tickSize) * tickValue;
   if(pipValue == 0.0) return 0.01;

   double lots = InpRiskUSD / (slPips * pipValue);
   double lotStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
   double lotMin  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double lotMax  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);

   lots = MathFloor(lots / lotStep) * lotStep;
   lots = MathMax(lotMin, MathMin(lotMax, lots));
   return NormalizeDouble(lots, 2);
  }

//+------------------------------------------------------------------+
//|  ColocarOrdenes                                                  |
//+------------------------------------------------------------------+
void ColocarOrdenes()
  {
   double sl_dist = InpSL_Pips  * g_PipSize;
   double tp_dist = InpTP_Pips  * g_PipSize;
   double lots    = CalculateLotSize(InpSL_Pips);

   if(lots <= 0.0) { Print("Error: lote calculado = 0"); return; }

   bool colocadaAlguna = false;

   // BUY STOP
   if(g_DirEfectiva == DIR_BOTH || g_DirEfectiva == DIR_BUY_ONLY)
     {
      double entryBuy = g_RangeHigh + _Point;
      double slBuy    = entryBuy - sl_dist;
      double tpBuy    = entryBuy + tp_dist;

      if(g_Trade.BuyStop(lots, NormalizeDouble(entryBuy, _Digits),
                          _Symbol,
                          NormalizeDouble(slBuy, _Digits),
                          NormalizeDouble(tpBuy, _Digits),
                          ORDER_TIME_DAY, 0, "ORB_NY_BUY"))
        {
         g_TicketBuy = g_Trade.ResultOrder();
         colocadaAlguna = true;
         Print("BUY STOP colocado | Entry=", entryBuy, " SL=", slBuy, " TP=", tpBuy, " Lots=", lots);
        }
      else
         Print("Error BUY STOP: ", g_Trade.ResultRetcodeDescription());
     }

   // SELL STOP
   if(g_DirEfectiva == DIR_BOTH || g_DirEfectiva == DIR_SELL_ONLY)
     {
      double entrySell = g_RangeLow - _Point;
      double slSell    = entrySell + sl_dist;
      double tpSell    = entrySell - tp_dist;

      if(g_Trade.SellStop(lots, NormalizeDouble(entrySell, _Digits),
                           _Symbol,
                           NormalizeDouble(slSell, _Digits),
                           NormalizeDouble(tpSell, _Digits),
                           ORDER_TIME_DAY, 0, "ORB_NY_SELL"))
        {
         g_TicketSell = g_Trade.ResultOrder();
         colocadaAlguna = true;
         Print("SELL STOP colocado | Entry=", entrySell, " SL=", slSell, " TP=", tpSell, " Lots=", lots);
        }
      else
         Print("Error SELL STOP: ", g_Trade.ResultRetcodeDescription());
     }

   if(colocadaAlguna)
     {
      g_OrdenesColocadas     = true;
      g_OrdenesColocadasTime = TimeCurrent();
      g_UltimaVelaContada    = iTime(_Symbol, PERIOD_M5, 0);
      g_VelasDesdeColocacion = 0;
     }
  }

//+------------------------------------------------------------------+
//|  GestionarExpiracion  (logica v2b)                               |
//+------------------------------------------------------------------+
void GestionarExpiracion()
  {
   if(InpOrdenExpiraVelas <= 0) return;
   if(g_TicketPos != 0) return;
   if(PositionSelectByTicket(g_TicketPos)) return;

   datetime velaActual = iTime(_Symbol, PERIOD_M5, 0);
   if(velaActual != g_UltimaVelaContada)
     {
      g_VelasDesdeColocacion++;
      g_UltimaVelaContada = velaActual;
     }

   if(g_VelasDesdeColocacion >= InpOrdenExpiraVelas)
     {
      Print("Expiracion activada (", InpOrdenExpiraVelas, " velas). Cancelando ordenes pendientes.");
      CancelarOrdenPendiente(g_TicketBuy);
      CancelarOrdenPendiente(g_TicketSell);
      g_OrdenesColocadas = false;
      g_OperadoHoy       = true;
     }
  }

//+------------------------------------------------------------------+
//|  CancelarOrdenPendiente                                          |
//+------------------------------------------------------------------+
void CancelarOrdenPendiente(ulong &ticket)
  {
   if(ticket == 0) return;
   if(OrderSelect(ticket))
     {
      g_Trade.OrderDelete(ticket);
      Print("Orden cancelada: ", ticket);
     }
   ticket = 0;
  }

//+------------------------------------------------------------------+
//|  VerificarActivacion                                             |
//+------------------------------------------------------------------+
void VerificarActivacion()
  {
   bool buyActivo  = (g_TicketBuy  != 0 && PositionSelectByTicket(g_TicketBuy));
   bool sellActivo = (g_TicketSell != 0 && PositionSelectByTicket(g_TicketSell));

   if(buyActivo)
     {
      g_TicketPos  = g_TicketBuy;
      g_OperadoHoy = true;
      CancelarOrdenPendiente(g_TicketSell);
      Print("BUY activado. SELL cancelado. Timer inactivo.");
     }
   else if(sellActivo)
     {
      g_TicketPos  = g_TicketSell;
      g_OperadoHoy = true;
      CancelarOrdenPendiente(g_TicketBuy);
      Print("SELL activado. BUY cancelado. Timer inactivo.");
     }
  }

//+------------------------------------------------------------------+
//|  GestionarPosicion  — BreakEven                                  |
//+------------------------------------------------------------------+
void GestionarPosicion()
  {
   if(g_TicketPos == 0) return;
   if(!PositionSelectByTicket(g_TicketPos)) { g_TicketPos = 0; return; }

   if(InpBE_Pips <= 0.0) return;

   double be_dist   = InpBE_Pips * g_PipSize;
   double openPrice = PositionGetDouble(POSITION_PRICE_OPEN);
   double currentSL = PositionGetDouble(POSITION_SL);
   double bid       = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double ask       = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   long   posType   = PositionGetInteger(POSITION_TYPE);

   if(posType == POSITION_TYPE_BUY)
     {
      if(bid >= openPrice + be_dist)
        {
         double newSL = openPrice + _Point;
         if(currentSL < newSL - _Point)
           {
            g_Trade.PositionModify(g_TicketPos, NormalizeDouble(newSL, _Digits),
                                    PositionGetDouble(POSITION_TP));
            Print("BreakEven BUY activado en ", newSL);
           }
        }
     }
   else if(posType == POSITION_TYPE_SELL)
     {
      if(ask <= openPrice - be_dist)
        {
         double newSL = openPrice - _Point;
         if(currentSL > newSL + _Point || currentSL == 0.0)
           {
            g_Trade.PositionModify(g_TicketPos, NormalizeDouble(newSL, _Digits),
                                    PositionGetDouble(POSITION_TP));
            Print("BreakEven SELL activado en ", newSL);
           }
        }
     }
  }

//+------------------------------------------------------------------+
//|  VISUALES                                                        |
//+------------------------------------------------------------------+
void DibujarRango()
  {
   if(!InpShowVisuals) return;

   string prefH = InpObjPrefix + "RangeHigh";
   string prefL = InpObjPrefix + "RangeLow";

   if(ObjectFind(0, prefH) >= 0) ObjectDelete(0, prefH);
   if(ObjectFind(0, prefL) >= 0) ObjectDelete(0, prefL);

   datetime t1 = g_RangeTime;
   datetime t2 = t1 + 86400;

   ObjectCreate(0, prefH, OBJ_TREND, 0, t1, g_RangeHigh, t2, g_RangeHigh);
   ObjectSetInteger(0, prefH, OBJPROP_COLOR,  clrMediumPurple);
   ObjectSetInteger(0, prefH, OBJPROP_WIDTH,  2);
   ObjectSetInteger(0, prefH, OBJPROP_RAY_RIGHT, true);
   ObjectSetString (0, prefH, OBJPROP_TOOLTIP, "ORCA NY Range High");

   ObjectCreate(0, prefL, OBJ_TREND, 0, t1, g_RangeLow, t2, g_RangeLow);
   ObjectSetInteger(0, prefL, OBJPROP_COLOR,  clrCrimson);
   ObjectSetInteger(0, prefL, OBJPROP_WIDTH,  2);
   ObjectSetInteger(0, prefL, OBJPROP_RAY_RIGHT, true);
   ObjectSetString (0, prefL, OBJPROP_TOOLTIP, "ORCA NY Range Low");
  }

//+------------------------------------------------------------------+
//|  ActualizarPanel                                                 |
//+------------------------------------------------------------------+
void ActualizarPanel()
  {
   if(!InpShowVisuals) return;

   string dir  = (g_DirEfectiva == DIR_BUY_ONLY)  ? "BUY ONLY" :
                 (g_DirEfectiva == DIR_SELL_ONLY)  ? "SELL ONLY" : "BOTH";
   string orca = InpORCA_Activo ? StringFormat("ORCA: %.4f [%s]", g_ORCA_Score, dir) : "ORCA: OFF";

   string countdown = "";
   if(g_OrdenesColocadas && InpOrdenExpiraVelas > 0 && g_TicketPos == 0)
     {
      int restantes = InpOrdenExpiraVelas - g_VelasDesdeColocacion;
      int minutos   = restantes * 5;
      countdown = StringFormat(" | Expira: %d velas (%d min)", restantes, minutos);
     }

   string panel = StringFormat(
      "ORB v3 ORCA NY | %s\n"
      "Sesion: %02d:%02d | Candles: %d | RR: %.1f:1\n"
      "Rango: %s | Ordenes: %s | Operado: %s\n"
      "%s%s",
      _Symbol,
      InpSessionHour, InpSessionMinute, InpRangeCandles,
      (InpSL_Pips > 0) ? InpTP_Pips / InpSL_Pips : 0.0,
      g_RangoFormado  ? StringFormat("H=%.2f L=%.2f", g_RangeHigh, g_RangeLow) : "Pendiente",
      g_OrdenesColocadas ? "SI" : "NO",
      g_OperadoHoy    ? "SI" : "NO",
      orca, countdown);

   Comment(panel);
  }

//+------------------------------------------------------------------+
//|  EliminarObjetos                                                 |
//+------------------------------------------------------------------+
void EliminarObjetos()
  {
   int total = ObjectsTotal(0);
   for(int i = total - 1; i >= 0; i--)
     {
      string name = ObjectName(0, i);
      if(StringFind(name, InpObjPrefix) == 0)
         ObjectDelete(0, name);
     }
   Comment("");
  }
//+------------------------------------------------------------------+

display_content.json_block:
{"language": "plaintext", "code": "//+------------------------------------------------------------------+
//|  ORB_BreakoutEA_v3_ORCA_NY_XAUUSD.mq5                           |
//|  Jose's Trading Suite  |  Abril 2026                            |
//|  Sesion: NY Open  |  Pass #2210 (Optimizacion ORCA)             |
//|  Magic: 20260505  |  Prefijo objetos: ORB_v3_ORCA_NY_           |
//|  Base: v2b (InpOrdenExpiraVelas) + Filtro ORCA integrado        |
//|                                                                  |
//|  Parametros optimos:                                             |
//|    SessionHour=17, SessionMinute=0, RangeCandles=5              |
//|    TP=100, SL=50, BE=80, Risk=$25                               |
//|    ORCA: Peso=0.7, Umbral=0.15                                  |
//+------------------------------------------------------------------+
#property copyright "Jose's Trading Suite"
#property version   "3.05"
#property strict

#include <Trade\Trade.mqh>

//--- Enumeraciones
enum ENUM_TRADE_DIR
  {
   DIR_BOTH      = 0,
   DIR_BUY_ONLY  = 1,
   DIR_SELL_ONLY = 2
  };

//+------------------------------------------------------------------+
//|  INPUTS                                                          |
//+------------------------------------------------------------------+
input group "=== SESION ==="
input int              InpSessionHour         = 17;     // Hora inicio sesion (servidor)
input int              InpSessionMinute        = 0;     // Minuto inicio sesion
input int              InpRangeCandles        = 5;      // Velas M5 para construir rango

input group "=== GESTION ==="
input double           InpTP_Pips             = 100.0;  // Take Profit (pips)
input double           InpSL_Pips             = 50.0;   // Stop Loss (pips)
input double           InpBE_Pips             = 80.0;   // BreakEven (0=desactivado)
input double           InpRiskUSD             = 25.0;   // Riesgo por trade (USD)
input ENUM_TRADE_DIR   InpTradeDirection      = DIR_BOTH;// Direccion permitida

input group "=== EXPIRACION ORDENES (v2b) ==="
input int              InpOrdenExpiraVelas    = 0;      // Velas M5 para expirar (0=sin limite)

input group "=== FILTRO ORCA ==="
input bool             InpORCA_Activo         = true;   // Activar filtro ORCA
input double           InpORCA_PesoBullPressure = 0.7;  // Peso BullPressure (0-1)
input double           InpORCA_UmbralScore    = 0.15;   // Umbral score ORCA (0-1)

input group "=== DIAS PERMITIDOS ==="
input bool             InpAllowMonday         = true;
input bool             InpAllowTuesday        = true;
input bool             InpAllowWednesday      = true;
input bool             InpAllowThursday       = true;
input bool             InpAllowFriday         = true;
input bool             InpAllowSaturday       = false;
input bool             InpAllowSunday         = false;

input group "=== CONFIGURACION ==="
input bool             InpOnlyOnePerDay       = true;   // Solo un trade por dia
input long             InpMagicNumber         = 20260505;
input bool             InpShowVisuals         = true;   // Mostrar panel (false en backtest)
input string           InpObjPrefix           = "ORB_v3_ORCA_NY_";

//+------------------------------------------------------------------+
//|  VARIABLES GLOBALES                                              |
//+------------------------------------------------------------------+
CTrade   g_Trade;
double   g_PipSize        = 0.0;

// Estado del rango
bool     g_RangoFormado   = false;
double   g_RangeHigh      = 0.0;
double   g_RangeLow       = 0.0;
datetime g_RangeTime      = 0;

// ORCA score calculado en BuildRange
double   g_ORCA_Score     = 0.0;
ENUM_TRADE_DIR g_DirEfectiva = DIR_BOTH;

// Estado de ordenes
bool     g_OrdenesColocadas  = false;
bool     g_OperadoHoy        = false;
datetime g_OrdenesColocadasTime = 0;
datetime g_UltimaVelaContada = 0;
int      g_VelasDesdeColocacion = 0;

// Tickets
ulong    g_TicketBuy      = 0;
ulong    g_TicketSell     = 0;
ulong    g_TicketPos      = 0;

// Control de dia
datetime g_UltimoDia      = 0;

//+------------------------------------------------------------------+
//|  OnInit                                                          |
//+------------------------------------------------------------------+
int OnInit()
  {
   g_PipSize = _Point * 10.0;
   g_Trade.SetExpertMagicNumber(InpMagicNumber);
   g_Trade.SetDeviationInPoints(30);
   g_Trade.SetTypeFilling(ORDER_FILLING_IOC);

   Print("ORB_v3_ORCA_NY iniciado | Magic=", InpMagicNumber,
         " | Sesion=", InpSessionHour, ":", StringFormat("%02d", InpSessionMinute),
         " | Candles=", InpRangeCandles,
         " | TP=", InpTP_Pips, " SL=", InpSL_Pips, " BE=", InpBE_Pips,
         " | ORCA=", InpORCA_Activo, " Peso=", InpORCA_PesoBullPressure, " Umbral=", InpORCA_UmbralScore);

   ResetDia();
   return INIT_SUCCEEDED;
  }

//+------------------------------------------------------------------+
//|  OnDeinit                                                        |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
  {
   EliminarObjetos();
  }

//+------------------------------------------------------------------+
//|  OnTick                                                          |
//+------------------------------------------------------------------+
void OnTick()
  {
   // Verificar nuevo dia
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);

   datetime inicioDia = StringToTime(StringFormat("%04d.%02d.%02d 00:00", dt.year, dt.mon, dt.day));
   if(inicioDia != g_UltimoDia)
     {
      ResetDia();
      g_UltimoDia = inicioDia;
     }

   // Verificar dia permitido
   if(!DiaPermitido(dt.day_of_week)) return;

   // Si ya opero hoy y OnlyOnePerDay -> solo gestionar
   if(g_OperadoHoy && InpOnlyOnePerDay)
     {
      GestionarPosicion();
      if(InpShowVisuals) ActualizarPanel();
      return;
     }

   // Construir rango si no esta formado
   if(!g_RangoFormado)
     {
      TryBuildRange();
     }

   // Colocar ordenes si rango formado y no colocadas aun
   if(g_RangoFormado && !g_OrdenesColocadas && !g_OperadoHoy)
     {
      ColocarOrdenes();
     }

   // Gestionar expiracion v2b
   if(g_OrdenesColocadas && InpOrdenExpiraVelas > 0)
     {
      GestionarExpiracion();
     }

   // Verificar activacion de ordenes
   if(g_OrdenesColocadas)
     {
      VerificarActivacion();
     }

   // Gestionar posicion abierta
   GestionarPosicion();

   if(InpShowVisuals) ActualizarPanel();
  }

//+------------------------------------------------------------------+
//|  ResetDia                                                        |
//+------------------------------------------------------------------+
void ResetDia()
  {
   g_RangoFormado    = false;
   g_RangeHigh       = 0.0;
   g_RangeLow        = 0.0;
   g_RangeTime       = 0;
   g_ORCA_Score      = 0.0;
   g_DirEfectiva     = DIR_BOTH;
   g_OrdenesColocadas= false;
   g_OperadoHoy      = false;
   g_OrdenesColocadasTime = 0;
   g_UltimaVelaContada    = 0;
   g_VelasDesdeColocacion = 0;
   g_TicketBuy       = 0;
   g_TicketSell      = 0;
   g_TicketPos       = 0;

   EliminarObjetos();
  }

//+------------------------------------------------------------------+
//|  DiaPermitido                                                    |
//+------------------------------------------------------------------+
bool DiaPermitido(int diaSemana)
  {
   switch(diaSemana)
     {
      case 0: return InpAllowSunday;
      case 1: return InpAllowMonday;
      case 2: return InpAllowTuesday;
      case 3: return InpAllowWednesday;
      case 4: return InpAllowThursday;
      case 5: return InpAllowFriday;
      case 6: return InpAllowSaturday;
     }
   return false;
  }

//+------------------------------------------------------------------+
//|  TryBuildRange  — construye rango + calcula ORCA en un solo loop |
//+------------------------------------------------------------------+
void TryBuildRange()
  {
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);

   // Tiempo de inicio de sesion hoy
   datetime sesionInicio = StringToTime(StringFormat("%04d.%02d.%02d %02d:%02d",
                           dt.year, dt.mon, dt.day,
                           InpSessionHour, InpSessionMinute));

   if(TimeCurrent() < sesionInicio) return;

   // Necesitamos InpRangeCandles velas M5 completas desde sesionInicio
   int totalBars = Bars(_Symbol, PERIOD_M5);
   if(totalBars < InpRangeCandles + 2) return;

   // Encontrar la barra que corresponde a sesionInicio
   int barInicio = iBarShift(_Symbol, PERIOD_M5, sesionInicio, false);
   if(barInicio < 0) return;

   // Verificar que todas las velas del rango estan cerradas
   int barFin = barInicio - (InpRangeCandles - 1);
   if(barFin <= 0) return;

   // Construir High/Low + ORCA en un solo loop
   double rangeHigh = 0.0, rangeLow = DBL_MAX;
   double sumBody = 0.0;
   double bullishBody = 0.0;
   int    n = InpRangeCandles;

   for(int i = barInicio; i >= barFin; i--)
     {
      double hi  = iHigh(_Symbol, PERIOD_M5, i);
      double lo  = iLow (_Symbol, PERIOD_M5, i);
      double op  = iOpen(_Symbol, PERIOD_M5, i);
      double cl  = iClose(_Symbol, PERIOD_M5, i);

      if(hi > rangeHigh) rangeHigh = hi;
      if(lo < rangeLow)  rangeLow  = lo;

      double body = MathAbs(cl - op);
      sumBody += body;
      if(cl > op) bullishBody += body;
     }

   if(rangeHigh <= rangeLow) return;

   // MidBias: promedio de cierres normalizado dentro del rango
   double totalRange = rangeHigh - rangeLow;
   double midClose   = 0.0;
   for(int i = barInicio; i >= barFin; i--)
     {
      double cl = iClose(_Symbol, PERIOD_M5, i);
      midClose += (cl - rangeLow) / totalRange;
     }
   midClose /= n;

   double bullPressure = (sumBody > 0.0) ? (bullishBody / sumBody) : 0.5;
   double midBias      = midClose;

   double rawScore = InpORCA_PesoBullPressure * bullPressure +
                     (1.0 - InpORCA_PesoBullPressure) * midBias;
   g_ORCA_Score = rawScore - 0.5;

   // Aplicar filtro ORCA
   g_DirEfectiva = (ENUM_TRADE_DIR)InpTradeDirection;
   if(InpORCA_Activo)
     {
      if(g_ORCA_Score > InpORCA_UmbralScore)
         g_DirEfectiva = DIR_BUY_ONLY;
      else if(g_ORCA_Score < -InpORCA_UmbralScore)
         g_DirEfectiva = DIR_SELL_ONLY;
      else
         g_DirEfectiva = DIR_BOTH;

      if(InpTradeDirection == DIR_BUY_ONLY  && g_DirEfectiva == DIR_SELL_ONLY) g_DirEfectiva = DIR_BUY_ONLY;
      if(InpTradeDirection == DIR_SELL_ONLY && g_DirEfectiva == DIR_BUY_ONLY)  g_DirEfectiva = DIR_SELL_ONLY;
     }

   g_RangeHigh    = rangeHigh;
   g_RangeLow     = rangeLow;
   g_RangeTime    = sesionInicio;
   g_RangoFormado = true;

   Print("RANGO FORMADO | High=", DoubleToString(g_RangeHigh, _Digits),
         " Low=", DoubleToString(g_RangeLow, _Digits),
         " | ORCA Score=", DoubleToString(g_ORCA_Score, 4),
         " | Direccion=", g_DirEfectiva == DIR_BOTH ? "BOTH" :
                          g_DirEfectiva == DIR_BUY_ONLY ? "BUY" : "SELL");

   if(InpShowVisuals) DibujarRango();
  }

//+------------------------------------------------------------------+
//|  CalculateLotSize                                                |
//+------------------------------------------------------------------+
double CalculateLotSize(double slPips)
  {
   double tickValue = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   if(tickSize == 0.0 || tickValue == 0.0) return 0.01;

   double pipValue = (g_PipSize / tickSize) * tickValue;
   if(pipValue == 0.0) return 0.01;

   double lots = InpRiskUSD / (slPips * pipValue);
   double lotStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
   double lotMin  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double lotMax  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);

   lots = MathFloor(lots / lotStep) * lotStep;
   lots = MathMax(lotMin, MathMin(lotMax, lots));
   return NormalizeDouble(lots, 2);
  }

//+------------------------------------------------------------------+
//|  ColocarOrdenes                                                  |
//+------------------------------------------------------------------+
void ColocarOrdenes()
  {
   double sl_dist = InpSL_Pips  * g_PipSize;
   double tp_dist = InpTP_Pips  * g_PipSize;
   double lots    = CalculateLotSize(InpSL_Pips);

   if(lots <= 0.0) { Print("Error: lote calculado = 0"); return; }

   bool colocadaAlguna = false;

   // BUY STOP
   if(g_DirEfectiva == DIR_BOTH || g_DirEfectiva == DIR_BUY_ONLY)
     {
      double entryBuy = g_RangeHigh + _Point;
      double slBuy    = entryBuy - sl_dist;
      double tpBuy    = entryBuy + tp_dist;

      if(g_Trade.BuyStop(lots, NormalizeDouble(entryBuy, _Digits),
                          _Symbol,
                          NormalizeDouble(slBuy, _Digits),
                          NormalizeDouble(tpBuy, _Digits),
                          ORDER_TIME_DAY, 0, "ORB_NY_BUY"))
        {
         g_TicketBuy = g_Trade.ResultOrder();
         colocadaAlguna = true;
         Print("BUY STOP colocado | Entry=", entryBuy, " SL=", slBuy, " TP=", tpBuy, " Lots=", lots);
        }
      else
         Print("Error BUY STOP: ", g_Trade.ResultRetcodeDescription());
     }

   // SELL STOP
   if(g_DirEfectiva == DIR_BOTH || g_DirEfectiva == DIR_SELL_ONLY)
     {
      double entrySell = g_RangeLow - _Point;
      double slSell    = entrySell + sl_dist;
      double tpSell    = entrySell - tp_dist;

      if(g_Trade.SellStop(lots, NormalizeDouble(entrySell, _Digits),
                           _Symbol,
                           NormalizeDouble(slSell, _Digits),
                           NormalizeDouble(tpSell, _Digits),
                           ORDER_TIME_DAY, 0, "ORB_NY_SELL"))
        {
         g_TicketSell = g_Trade.ResultOrder();
         colocadaAlguna = true;
         Print("SELL STOP colocado | Entry=", entrySell, " SL=", slSell, " TP=", tpSell, " Lots=", lots);
        }
      else
         Print("Error SELL STOP: ", g_Trade.ResultRetcodeDescription());
     }

   if(colocadaAlguna)
     {
      g_OrdenesColocadas     = true;
      g_OrdenesColocadasTime = TimeCurrent();
      g_UltimaVelaContada    = iTime(_Symbol, PERIOD_M5, 0);
      g_VelasDesdeColocacion = 0;
     }
  }

//+------------------------------------------------------------------+
//|  GestionarExpiracion  (logica v2b)                               |
//+------------------------------------------------------------------+
void GestionarExpiracion()
  {
   if(InpOrdenExpiraVelas <= 0) return;
   if(g_TicketPos != 0) return;
   if(PositionSelectByTicket(g_TicketPos)) return;

   datetime velaActual = iTime(_Symbol, PERIOD_M5, 0);
   if(velaActual != g_UltimaVelaContada)
     {
      g_VelasDesdeColocacion++;
      g_UltimaVelaContada = velaActual;
     }

   if(g_VelasDesdeColocacion >= InpOrdenExpiraVelas)
     {
      Print("Expiracion activada (", InpOrdenExpiraVelas, " velas). Cancelando ordenes pendientes.");
      CancelarOrdenPendiente(g_TicketBuy);
      CancelarOrdenPendiente(g_TicketSell);
      g_OrdenesColocadas = false;
      g_OperadoHoy       = true;
     }
  }

//+------------------------------------------------------------------+
//|  CancelarOrdenPendiente                                          |
//+------------------------------------------------------------------+
void CancelarOrdenPendiente(ulong &ticket)
  {
   if(ticket == 0) return;
   if(OrderSelect(ticket))
     {
      g_Trade.OrderDelete(ticket);
      Print("Orden cancelada: ", ticket);
     }
   ticket = 0;
  }

//+------------------------------------------------------------------+
//|  VerificarActivacion                                             |
//+------------------------------------------------------------------+
void VerificarActivacion()
  {
   bool buyActivo  = (g_TicketBuy  != 0 && PositionSelectByTicket(g_TicketBuy));
   bool sellActivo = (g_TicketSell != 0 && PositionSelectByTicket(g_TicketSell));

   if(buyActivo)
     {
      g_TicketPos  = g_TicketBuy;
      g_OperadoHoy = true;
      CancelarOrdenPendiente(g_TicketSell);
      Print("BUY activado. SELL cancelado. Timer inactivo.");
     }
   else if(sellActivo)
     {
      g_TicketPos  = g_TicketSell;
      g_OperadoHoy = true;
      CancelarOrdenPendiente(g_TicketBuy);
      Print("SELL activado. BUY cancelado. Timer inactivo.");
     }
  }

//+------------------------------------------------------------------+
//|  GestionarPosicion  — BreakEven                                  |
//+------------------------------------------------------------------+
void GestionarPosicion()
  {
   if(g_TicketPos == 0) return;
   if(!PositionSelectByTicket(g_TicketPos)) { g_TicketPos = 0; return; }

   if(InpBE_Pips <= 0.0) return;

   double be_dist   = InpBE_Pips * g_PipSize;
   double openPrice = PositionGetDouble(POSITION_PRICE_OPEN);
   double currentSL = PositionGetDouble(POSITION_SL);
   double bid       = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double ask       = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   long   posType   = PositionGetInteger(POSITION_TYPE);

   if(posType == POSITION_TYPE_BUY)
     {
      if(bid >= openPrice + be_dist)
        {
         double newSL = openPrice + _Point;
         if(currentSL < newSL - _Point)
           {
            g_Trade.PositionModify(g_TicketPos, NormalizeDouble(newSL, _Digits),
                                    PositionGetDouble(POSITION_TP));
            Print("BreakEven BUY activado en ", newSL);
           }
        }
     }
   else if(posType == POSITION_TYPE_SELL)
     {
      if(ask <= openPrice - be_dist)
        {
         double newSL = openPrice - _Point;
         if(currentSL > newSL + _Point || currentSL == 0.0)
           {
            g_Trade.PositionModify(g_TicketPos, NormalizeDouble(newSL, _Digits),
                                    PositionGetDouble(POSITION_TP));
            Print("BreakEven SELL activado en ", newSL);
           }
        }
     }
  }

//+------------------------------------------------------------------+
//|  VISUALES                                                        |
//+------------------------------------------------------------------+
void DibujarRango()
  {
   if(!InpShowVisuals) return;

   string prefH = InpObjPrefix + "RangeHigh";
   string prefL = InpObjPrefix + "RangeLow";

   if(ObjectFind(0, prefH) >= 0) ObjectDelete(0, prefH);
   if(ObjectFind(0, prefL) >= 0) ObjectDelete(0, prefL);

   datetime t1 = g_RangeTime;
   datetime t2 = t1 + 86400;

   ObjectCreate(0, prefH, OBJ_TREND, 0, t1, g_RangeHigh, t2, g_RangeHigh);
   ObjectSetInteger(0, prefH, OBJPROP_COLOR,  clrMediumPurple);
   ObjectSetInteger(0, prefH, OBJPROP_WIDTH,  2);
   ObjectSetInteger(0, prefH, OBJPROP_RAY_RIGHT, true);
   ObjectSetString (0, prefH, OBJPROP_TOOLTIP, "ORCA NY Range High");

   ObjectCreate(0, prefL, OBJ_TREND, 0, t1, g_RangeLow, t2, g_RangeLow);
   ObjectSetInteger(0, prefL, OBJPROP_COLOR,  clrCrimson);
   ObjectSetInteger(0, prefL, OBJPROP_WIDTH,  2);
   ObjectSetInteger(0, prefL, OBJPROP_RAY_RIGHT, true);
   ObjectSetString (0, prefL, OBJPROP_TOOLTIP, "ORCA NY Range Low");
  }

//+------------------------------------------------------------------+
//|  ActualizarPanel                                                 |
//+------------------------------------------------------------------+
void ActualizarPanel()
  {
   if(!InpShowVisuals) return;

   string dir  = (g_DirEfectiva == DIR_BUY_ONLY)  ? "BUY ONLY" :
                 (g_DirEfectiva == DIR_SELL_ONLY)  ? "SELL ONLY" : "BOTH";
